# WRITE_TARGET='backend/tests/performance/test_detour_performance.py'\n# WRITE_CONTENT_LENGTH=0\n\n'''Performance tests for Detour system.\n\nThese tests verify that key operations meet the performance targets\nspecified in the implementation plan.\n'''\n\nimport time\nfrom datetime import datetime, timezone\n\nimport pytest\nfrom app.db.base import generate_uuid\nfrom app.db.models.ontology import Satellite, Orbit, ConjunctionEvent\nfrom app.db.models.detour import DetourConjunctionAnalysis, DetourManeuverPlan\nfrom app.services.detour.state_manager import DetourStateManager\nfrom app.agents.detour.tools import screen_conjunctions_tool\nfrom app.agents.detour.graph import run_detour_pipeline, stream_detour_pipeline\n\ndef dummy_tle(norad_id: int) -> tuple[str, str]:\n    line1 = f'1 {norad_id:05d}U 20000A   24001.00000000  .00000000  00000-0  00000-0 0  9991'\n    line2 = f'2 {norad_id:05d}  98.0000   0.0000 0000001  0.0000   0.0000 14.00000000    01'\n    return line1, line2\n\n@pytest.mark.asyncio\nasync def test_screening_performance(db_session):\n    '''Screening 1000 objects should complete in <5 seconds.'''\n    primary = Satellite(id=generate_uuid(), norad_id=10001, name='PrimSat', object_type='satellite')\n    db_session.add(primary)\n    await db_session.flush()\n    tle1, tle2 = dummy_tle(10001)\n    primary_orbit = Orbit(id=generate_uuid(), satellite_id=primary.id, epoch=datetime.utcnow(), tle_line1=tle1, tle_line2=tle2)\n    db_session.add(primary_orbit)\n    await db_session.flush()\n    for i in range(1000):\n        sat = Satellite(id=generate_uuid(), norad_id=20000 + i, name=f'SecSat{i}', object_type='satellite')\n        db_session.add(sat)\n        await db_session.flush()\n        tle_sec1, tle_sec2 = dummy_tle(20000 + i)\n        orbit = Orbit(id=generate_uuid(), satellite_id=sat.id, epoch=datetime.utcnow(), tle_line1=tle_sec1, tle_line2=tle_sec2)\n        db_session.add(orbit)\n        await db_session.flush()\n    start = time.perf_counter()\n    result = await screen_conjunctions_tool(satellite_id=primary.id, db=db_session)\n    elapsed = time.perf_counter() - start\n    assert isinstance(result, dict)\n    assert 'screening_results' in result\n    assert elapsed < 5.0, f'Screening took {elapsed:.2f}s, exceeds 5s limit'\n\n@pytest.mark.asyncio\nasync def test_pipeline_latency_performance(db_session):\n    '''Full pipeline should complete in <30 seconds (low‑risk case).'''\n    primary = Satellite(id=generate_uuid(), norad_id=30001, name='PrimSatLow', object_type='satellite')\n    secondary = Satellite(id=generate_uuid(), norad_id=30002, name='SecSatLow', object_type='satellite')\n    db_session.add_all([primary, secondary])\n    await db_session.flush()\n    tle_primary = dummy_tle(30001)\n    primary_orbit = Orbit(id=generate_uuid(), satellite_id=primary.id, epoch=datetime.utcnow(), tle_line1=tle_primary[0], tle_line2=tle_primary[1])\n    tle_secondary = dummy_tle(30002)\n    secondary_orbit = Orbit(id=generate_uuid(), satellite_id=secondary.id, epoch=datetime.utcnow(), tle_line1=tle_secondary[0], tle_line2=tle_secondary[1])\n    db_session.add_all([primary_orbit, secondary_orbit])\n    await db_session.flush()\n    conj = ConjunctionEvent(\n        id=generate_uuid(),\n        primary_object_id=primary.id,\n        secondary_object_id=secondary.id,\n        tca=datetime.utcnow().replace(tzinfo=timezone.utc),\n        miss_distance_km=20.0,\n        risk_level='low',\n        collision_probability=1e-6,\n    )\n    db_session.add(conj)\n    await db_session.flush()\n    analysis = DetourConjunctionAnalysis(\n        id=generate_uuid(),\n        conjunction_event_id=conj.id,\n        tenant_id='default',\n        risk_level=conj.risk_level,\n        miss_distance_km=conj.miss_distance_km,\n        tca=conj.tca,\n        collision_probability=conj.collision_probability,\n        analysis_status='pending',\n    )\n    db_session.add(analysis)\n    await db_session.flush()\n    state_manager = DetourStateManager(db_session)\n    session_id = generate_uuid()\n    start = time.perf_counter()\n    final_state = await run_detour_pipeline(\n        session_id=session_id,\n        satellite_id=primary.id,\n        conjunction_event_id=conj.id,\n        tenant_id='default',\n        state_manager=state_manager,\n    )\n    elapsed = time.perf_counter() - start\n    assert final_state['completed'] is True\n    assert elapsed < 30.0, f'Pipeline latency {elapsed:.2f}s exceeds 30s limit'\n\n@pytest.mark.asyncio\nasync def test_sse_stream_performance(db_session):\n    '''Streaming the graph should produce 5 state updates quickly.'''\n    primary = Satellite(id=generate_uuid(), norad_id=40001, name='PrimSatSSE', object_type='satellite')\n    secondary = Satellite(id=generate_uuid(), norad_id=40002, name='SecSatSSE', object_type='satellite')\n    db_session.add_all([primary, secondary])\n    await db_session.flush()\n    tle_primary = dummy_tle(40001)\n    primary_orbit = Orbit(id=generate_uuid(), satellite_id=primary.id, epoch=datetime.utcnow(), tle_line1=tle_primary[0], tle_line2=tle_primary[1])\n    tle_secondary = dummy_tle(40002)\n    secondary_orbit = Orbit(id=generate_uuid(), satellite_id=secondary.id, epoch=datetime.utcnow(), tle_line1=tle_secondary[0], tle_line2=tle_secondary[1])\n    db_session.add_all([primary_orbit, secondary_orbit])\n    await db_session.flush()\n    conj = ConjunctionEvent(\n        id=generate_uuid(),\n        primary_object_id=primary.id,\n        secondary_object_id=secondary.id,\n        tca=datetime.utcnow().replace(tzinfo=timezone.utc),\n        miss_distance_km=15.0,\n        risk_level='low',\n        collision_probability=5e-7,\n    )\n    db_session.add(conj)\n    await db_session.flush()\n    analysis = DetourConjunctionAnalysis(\n        id=generate_uuid(),\n        conjunction_event_id=conj.id,\n        tenant_id='default',\n        risk_level=conj.risk_level,\n        miss_distance_km=conj.miss_distance_km,\n        tca=conj.tca,\n        collision_probability=conj.collision_probability,\n        analysis_status='pending',\n    )\n    db_session.add(analysis)\n    await db_session.flush()\n    state_manager = DetourStateManager(db_session)\n    session_id = generate_uuid()\n    start = time.perf_counter()\n    states = []\n    async for s in stream_detour_pipeline(\n        session_id=session_id,\n        satellite_id=primary.id,\n        conjunction_event_id=conj.id,\n        tenant_id='default',\n        state_manager=state_manager,\n    ):\n        states.append(s)\n    elapsed = time.perf_counter() - start\n    assert len(states) == 5\n    assert elapsed < 5.0, f'Streaming took {elapsed:.2f}s, exceeds 5s limit'\n\n@pytest.mark.asyncio\nasync def test_query_history_performance(db_session):\n    '''Maneuver history query should complete in <100 ms.'''\n    sat = Satellite(id=generate_uuid(), norad_id=50001, name='HistSat', object_type='satellite')\n    db_session.add(sat)\n    await db_session.flush()\n    conj = ConjunctionEvent(\n        id=generate_uuid(),\n        primary_object_id=sat.id,\n        secondary_object_id=sat.id,\n        tca=datetime.utcnow().replace(tzinfo=timezone.utc),\n        miss_distance_km=10.0,\n        risk_level='medium',\n        collision_probability=1e-5,\n    )\n    db_session.add(conj)\n    await db_session.flush()\n    analysis = DetourConjunctionAnalysis(\n        id=generate_uuid(),\n        conjunction_event_id=conj.id,\n        tenant_id='default',\n        risk_level=conj.risk_level,\n        miss_distance_km=conj.miss_distance_km,\n        tca=conj.tca,\n        collision_probability=conj.collision_probability,\n        analysis_status='pending',\n    )\n    db_session.add(analysis)\n    await db_session.flush()\n    for i in range(5):\n        plan = DetourManeuverPlan(\n            id=generate_uuid(),\n            conjunction_analysis_id=analysis.id,\n            tenant_id='default',\n            maneuver_type='in-plane',\n            delta_v_m_s=0.2,\n            fuel_cost_kg=10.0,\n        )\n        db_session.add(plan)\n    await db_session.flush()\n    state_manager = DetourStateManager(db_session)\n    start = time.perf_counter()\n    history = await state_manager.get_maneuver_history(satellite_id=sat.id, tenant_id='default')\n    elapsed = time.perf_counter() - start\n    assert isinstance(history, list)\n    assert len(history) == 5\n    assert elapsed < 0.1, f'History query took {elapsed:.3f}s exceeds 100 ms limit'\n